import React, { useState } from 'react';
import { ProductCard } from './ProductCard';
import './ProductList.css';

export const ProductList = ({ onAddToCart }) => {
  // Datos de productos (como el array de objetos de clase)
  const allProducts = [
    {
      id: 1,
      title: "Laptop Pro 15",
      description: "Laptop de alto rendimiento para desarrolladores y diseñadores.",
      price: 1200,
      image: "https://picsum.photos/id/0/300/200"
    },
    {
      id: 2,
      title: "Smartphone Z",
      description: "Cámara de 108MP, batería de larga duración y pantalla OLED.",
      price: 800,
      image: "https://picsum.photos/id/3/300/200"
    },
    {
      id: 3,
      title: "Auriculares Inalámbricos",
      description: "Cancelación de ruido activa y sonido envolvente.",
      price: 150,
      image: "https://picsum.photos/id/11/300/200"
    },
    {
      id: 4,
      title: "Monitor 4K 27'",
      description: "Monitor de alta resolución ideal para diseño gráfico.",
      price: 400,
      image: "https://picsum.photos/id/48/300/200"
    },
    {
      id: 5,
      title: "Teclado Mecánico RGB",
      description: "Switches azules, ideal para programación y gaming.",
      price: 85,
      image: "https://picsum.photos/id/36/300/200"
    },
    {
      id: 6,
      title: "Mouse Ergonómico",
      description: "Precisión óptica y diseño cómodo para largas horas de trabajo.",
      price: 45,
      image: "https://picsum.photos/id/2/300/200"
    }
  ];

  // Estado para la búsqueda (basado en el buscador que hizo el profesor con .filter)
  const [searchTerm, setSearchTerm] = useState("");

  const filteredProducts = allProducts.filter(product =>
    product.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <section className="product-section" id="productos">
      <h3 className="section-title">Catálogo de Productos</h3>
      
      {/* Buscador similar al de s7-ejercicio01.js */}
      <div className="search-container">
        <input 
          type="text" 
          placeholder="Buscar producto..." 
          className="search-input"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="product-container">
        {filteredProducts.map((product) => (
          <ProductCard 
            key={product.id}
            title={product.title} 
            description={product.description} 
            price={product.price}
            image={product.image} 
            onAdd={() => onAddToCart(product)}
          />
        ))}
      </div>
      {filteredProducts.length === 0 && <p className="no-results">No se encontraron productos.</p>}
    </section>
  );
};
